questions.explanation:
&lt;p&gt;&lt;strong&gt;The correct answer is -&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;None of the above.&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Aram Baksh&lt;/strong&gt;&lt;/u&gt; was the &lt;strong&gt;second ruler of the Slave&lt;/strong&gt; dynasty who ruled only for eight months after the death of Qutub-ud-din Aibak.&lt;/li&gt;
	&lt;li&gt;He assumed the title of Sultan Aram Shah after ascending the throne.&lt;/li&gt;
	&lt;li&gt;He was dethroned by Iltutmish in the year 1211.&lt;/li&gt;
&lt;/ul&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width:350px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;Ruler&lt;/strong&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;Period&lt;/strong&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;Important Achievements/Points&lt;/strong&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;Aram Baksh&lt;/td&gt;
			&lt;td&gt;1210-11 (8 months)&lt;/td&gt;
			&lt;td&gt;
			&lt;ul&gt;
				&lt;li&gt;He was an inexperienced and incapable ruler&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;Iltutmish&lt;/td&gt;
			&lt;td&gt;1211-1236&lt;/td&gt;
			&lt;td&gt;
			&lt;ul&gt;
				&lt;li&gt;He completed the famous Qutab Minar in Delhi.&lt;/li&gt;
				&lt;li&gt;He shifted his capital from Lahore to Delhi.&lt;/li&gt;
				&lt;li&gt;The Mongol policy of Iltutmish saved India from the wrath of Ghengis&amp;nbsp;Khan.&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;Razia Sultana&lt;/td&gt;
			&lt;td&gt;1236-40&lt;/td&gt;
			&lt;td&gt;
			&lt;ul&gt;
				&lt;li&gt;She was the first female ruler of India.&lt;/li&gt;
				&lt;li&gt;Her term was full of revolts.&lt;/li&gt;
				&lt;li&gt;On October 13, 1240, she was killed by her&amp;nbsp;kin.&amp;nbsp;&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;Balban&lt;/td&gt;
			&lt;td&gt;1266-1287&lt;/td&gt;
			&lt;td&gt;
			&lt;ul&gt;
				&lt;li&gt;He was the greatest ruler of the Slave dynasty.&lt;/li&gt;
				&lt;li&gt;Balban started the rigorous court discipline and new customs such as prostration and kissing the Sultan&amp;#39;s feet to prove his superiority over the nobles.&lt;/li&gt;
				&lt;li&gt;He broke the power of Forty, the Turkish nobles, who were the real threat to&amp;nbsp;the monarchy.&lt;/li&gt;
				&lt;li&gt;His tomb is located in Mehrauli, Delhi&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;<br><br>&lt;p&gt;&lt;strong&gt;सही उत्तर है - &lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;उपर्युक्त में से कोई नहीं&lt;/span&gt;।&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;अराम बख्श&lt;/strong&gt;&lt;/u&gt; गुलाम वंश का दूसरा शासक था जिसने कुतुब-उद-दीन ऐबक की मृत्यु के बाद केवल आठ महीने तक शासन किया था।&lt;/li&gt;
	&lt;li&gt;उन्होंने गद्दी संभालने&amp;nbsp;के बाद सुल्तान अरम शाह की उपाधि धारण की थी।&lt;/li&gt;
	&lt;li&gt;उन्हें वर्ष 1211 में इल्तुतमिश द्वारा राजपद से हटा दिया&amp;nbsp;गया था।&lt;/li&gt;
&lt;/ul&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width:350px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;#58595b&quot;&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;शासक&lt;/span&gt;&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;#58595b&quot;&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;अवधि&lt;/span&gt;&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;#58595b&quot;&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;महत्वपूर्ण उपलब्धियां/बिंदु&lt;/span&gt;&lt;/font&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;&lt;font color=&quot;#58595b&quot;&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;अराम बख्श&lt;/span&gt;&lt;/font&gt;&lt;/td&gt;
			&lt;td&gt;&lt;font color=&quot;#58595b&quot;&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;1210-11 (8 महीने)&lt;/span&gt;&lt;/font&gt;&lt;/td&gt;
			&lt;td&gt;
			&lt;ul&gt;
				&lt;li&gt;&lt;font color=&quot;#58595b&quot;&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;वह एक अनुभवहीन और अक्षम शासक था&lt;/span&gt;&lt;/font&gt;&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;&lt;font color=&quot;#58595b&quot;&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;इल्तुतमिश&lt;/span&gt;&lt;/font&gt;&lt;/td&gt;
			&lt;td&gt;&lt;font color=&quot;#58595b&quot;&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;1211-1236&lt;/span&gt;&lt;/font&gt;&lt;/td&gt;
			&lt;td&gt;
			&lt;ul&gt;
				&lt;li&gt;&lt;font color=&quot;#58595b&quot;&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;उन्होंने दिल्ली में प्रसिद्ध कुतुब मीनार को पूरा किया था।&lt;/span&gt;&lt;/font&gt;&lt;/li&gt;
				&lt;li&gt;&lt;font color=&quot;#58595b&quot;&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;उन्होंने अपनी राजधानी लाहौर से दिल्ली स्थानांतरित कर दी थी।&lt;/span&gt;&lt;/font&gt;&lt;/li&gt;
				&lt;li&gt;&lt;font color=&quot;#58595b&quot;&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;इल्तुतमिश की मंगोल नीति ने भारत को&lt;/span&gt;&lt;/font&gt;
				&lt;p&gt;&lt;font color=&quot;#58595b&quot;&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;चंगेज&amp;nbsp;&lt;span style=&quot;background-color: transparent;&quot;&gt;खान के प्रकोप से बचाया था।&lt;/span&gt;&lt;/span&gt;&lt;/font&gt;&lt;/p&gt;
				&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;&lt;font color=&quot;#58595b&quot;&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;रजिया सुल्ताना&lt;/span&gt;&lt;/font&gt;&lt;/td&gt;
			&lt;td&gt;&lt;font color=&quot;#58595b&quot;&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;1236-40&lt;/span&gt;&lt;/font&gt;&lt;/td&gt;
			&lt;td&gt;
			&lt;ul&gt;
				&lt;li&gt;&lt;font color=&quot;#58595b&quot;&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;वह भारत की पहली महिला शासक थीं।&lt;/span&gt;&lt;/font&gt;&lt;/li&gt;
				&lt;li&gt;&lt;font color=&quot;#58595b&quot;&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;उनका कार्यकाल विद्रोहों से भरा था।&lt;/span&gt;&lt;/font&gt;&lt;/li&gt;
				&lt;li&gt;&lt;font color=&quot;#58595b&quot;&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;13 अक्टूबर, 1240 को, उसे उसके परिजनों ने मार डाला था।&amp;nbsp;&lt;/span&gt;&lt;/font&gt;&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;&lt;font color=&quot;#58595b&quot;&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;बलबन&lt;/span&gt;&lt;/font&gt;&lt;/td&gt;
			&lt;td&gt;&lt;font color=&quot;#58595b&quot;&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;1266-1287&lt;/span&gt;&lt;/font&gt;&lt;/td&gt;
			&lt;td&gt;
			&lt;ul&gt;
				&lt;li&gt;&lt;font color=&quot;#58595b&quot;&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;वह गुलाम वंश का सबसे बड़ा शासक था।&lt;/span&gt;&lt;/font&gt;&lt;/li&gt;
				&lt;li&gt;&lt;font color=&quot;#58595b&quot;&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;बलबन ने कुलीन वर्ग&amp;nbsp;पर अपनी श्रेष्ठता साबित करने के लिए कठोर अदालत अनुशासन और नई परम्पराओं जैसे&amp;nbsp;साष्टांग प्रणाम और सुल्तान के पैर को चुंबन देना शुरू किया था।&lt;/span&gt;&lt;/font&gt;&lt;/li&gt;
				&lt;li&gt;&lt;font color=&quot;#58595b&quot;&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;उसने तुर्की के कुलीन, फोर्टी की शक्ति को तोड़ दिया था, जो राजशाही के लिए वास्तविक खतरा थे।&lt;/span&gt;&lt;/font&gt;&lt;/li&gt;
				&lt;li&gt;&lt;font color=&quot;#58595b&quot;&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;उनका मकबरा दिल्ली के महरौली में स्थित है&lt;/span&gt;&lt;/font&gt;&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p style=&quot;color: (33, 37, 41);&quot;&gt;Correct Answer&amp;nbsp;&lt;strong&gt;Chir&lt;/strong&gt;&lt;/p&gt;

&lt;p style=&quot;color: (33, 37, 41);&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points:&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;color: (33, 37, 41);&quot;&gt;Indian forests perform an important role to make a&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;healthy environment and it reduces air pollutions.&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color: (33, 37, 41);&quot;&gt;
	&lt;li&gt;Near about&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;19.26%&lt;/span&gt;&amp;nbsp;of total Indian areas are covered with forest.&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;background-image: initial; background-attachment: initial; background-size: initial; background-origin: initial; background-clip: initial; background-position: initial; background-repeat: initial;&quot;&gt;Forests can be classified into&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;five major groups&lt;/span&gt;&amp;nbsp;namely:&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;background-image: initial; background-attachment: initial; background-size: initial; background-origin: initial; background-clip: initial; background-position: initial; background-repeat: initial;&quot;&gt;Moist tropical&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;background-image: initial; background-attachment: initial; background-size: initial; background-origin: initial; background-clip: initial; background-position: initial; background-repeat: initial;&quot;&gt;Dry tropical&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;background-image: initial; background-attachment: initial; background-size: initial; background-origin: initial; background-clip: initial; background-position: initial; background-repeat: initial;&quot;&gt;Montane temperate&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;background-image: initial; background-attachment: initial; background-size: initial; background-origin: initial; background-clip: initial; background-position: initial; background-repeat: initial;&quot;&gt;Montane subtropical&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;background-image: initial; background-attachment: initial; background-size: initial; background-origin: initial; background-clip: initial; background-position: initial; background-repeat: initial;&quot;&gt;Alpine forest&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;color: (33, 37, 41);&quot;&gt;&lt;span style=&quot;background-image: initial; background-attachment: initial; background-size: initial; background-origin: initial; background-clip: initial; background-position: initial; background-repeat: initial;&quot;&gt;&lt;img height=&quot;55px&quot; src=&quot;//storage.googleapis.com/tb-img/production/21/08/602faac86d082786b85cc85a_16298818453681.png&quot; width=&quot;180px&quot; /&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;color: (33, 37, 41);&quot;&gt;​&lt;span style=&quot;font-weight: bolder;&quot;&gt;Chir pine&amp;nbsp;or&amp;nbsp;longleaf Indian pine&lt;/span&gt;&amp;nbsp;is a species of&amp;nbsp;pine, native&amp;nbsp;to the&amp;nbsp;Himalayas.&lt;/p&gt;

&lt;ul style=&quot;color: (33, 37, 41);&quot;&gt;
	&lt;li&gt;It is found at an altitude of&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;1500-3000m.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;These trees are found in&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Montane Temperate forest.&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;These types of forests are mainly generated in the Northern middle Himalayas and Southern Niligiri higher Mountain ranges.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;Keekar and khair&lt;/strong&gt; trees are prevalent in the Semi-desert plains of Haryana.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Sundari trees&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color: (33, 37, 41);&quot;&gt;
	&lt;li&gt;Sundari trees are found in the Sunderbans&lt;/li&gt;
	&lt;li&gt;The wood of these trees is hard, oily, and durable.&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;It is used for making boats and other construction instruments.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;The Sundari Tree is one of the most extensively found mangrove species in the Sundarbans,&lt;/li&gt;
	&lt;li&gt;It is a large tree with wing-shaped nuts, which is most easily recognized by the silvery scales on the underside of its leaves.&lt;/li&gt;
	&lt;li&gt;Scientifically it is known as Heritiera littoralis.&lt;/li&gt;
	&lt;li&gt;The wood from the Sundari Tree is the chief source of timber among the people.&lt;/li&gt;
	&lt;li&gt;The wood is hard and red in color and yields good quality charcoal and is often used in boat building, and manufacturing hardwood floors and furniture.&lt;/li&gt;
	&lt;li&gt;It is also used in making pilings, bridges, and wharves.&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;color: (33, 37, 41);&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&lt;span style=&quot;vertical-align: middle; &quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;color: (33, 37, 41); width: 400px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;FOREST&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;RAINFALL&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;VEGETATION&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;REGION&lt;/font&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;Moist tropical&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;200 and 250 cm&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;Rosewood, bamboos, Kusum,&amp;nbsp;Indian chestnut, litsea&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;Western Coast, Upper Assam, lower slopes of the eastern Himalaya, Orissa coast&lt;/font&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;Dry tropical&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;51 cm to 151&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;Sal, acacia, mangoes and bamboo.&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;Northern Hilly regions and some states of Southern India&lt;/font&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;Montane temperate&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;150-250 cm&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;Ferns, oak, maple, juniper, deodar, chilgoza, chirpine&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;Northern middle Himalayas and Southern Niligiri higher Mountain ranges.&amp;nbsp;&lt;/font&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;Montane subtropical&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;150-300 cm&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;Cinnamon, rhododendron, sal, Sandan, laburnum, pomegranate, olive, oleander&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;Assam, Nagaland, Mizoram, Meghalaya, Manipur, Arunachal Pradesh&lt;/font&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;Alpine forest/Wet montane&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;100 cm&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;Black juniper, the drooping juniper; honeysuckle, and willows&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;Himalayan regions and the barren cold deserts of the Trans Himalaya.&amp;nbsp;&lt;/font&gt;&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;<br><br>&lt;p style=&quot;color: (33, 37, 41);&quot;&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;चीड़&lt;/strong&gt;&lt;/u&gt;&amp;nbsp;है।&amp;nbsp;&lt;/p&gt;

&lt;p style=&quot;color: (33, 37, 41);&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;font-size:20px;&quot;&gt;&lt;span style=&quot;vertical-align: middle;&quot;&gt;&lt;u&gt;Key Points:&lt;/u&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;भारतीय वन, एक &lt;strong&gt;स्वस्थ पर्यावरण&lt;/strong&gt; बनाने में महत्वपूर्ण भूमिका निभाते हैं, और यह&lt;strong&gt; वायु प्रदूषण को कम &lt;/strong&gt;करते हैं।&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;कुल भारतीय क्षेत्रों का लगभग &lt;strong&gt;19.26% &lt;/strong&gt;वनों से आच्छादित है।&lt;/li&gt;
	&lt;li&gt;वनों को &lt;strong&gt;पांच प्रमुख समूहों &lt;/strong&gt;में वर्गीकृत किया जा सकता है:
	&lt;ul&gt;
		&lt;li&gt;आर्द्र&amp;nbsp;उष्णकटिबंधीय&lt;/li&gt;
		&lt;li&gt;शुष्क उष्णकटिबंधीय&lt;/li&gt;
		&lt;li&gt;पर्वतीय समशीतोष्ण&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;color: (33, 37, 41);&quot;&gt;पर्वतीय&lt;/span&gt; उपोष्णकटिबंधीय&lt;/li&gt;
		&lt;li&gt;अल्पाइन वन&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;color: (33, 37, 41);&quot;&gt;&lt;span style=&quot;background-image: initial; background-attachment: initial; background-size: initial; background-origin: initial; background-clip: initial; background-position: initial; background-repeat: initial;&quot;&gt;&lt;img height=&quot;55px&quot; src=&quot;//storage.googleapis.com/tb-img/production/21/08/602faac86d082786b85cc85a_16298818453681.png&quot; width=&quot;180px&quot; /&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;color: (33, 37, 41);&quot;&gt;&lt;strong&gt;​चीड़ पाइन या लॉन्गलीफ इंडियन पाइन, &lt;/strong&gt;पाइन की एक प्रजाति है, जो मूलतः&amp;nbsp;हिमालय में पायी जाती है।&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;यह&lt;strong&gt; 1500-3000 मीटर&lt;/strong&gt; की ऊंचाई पर पाया जाता है।&lt;/li&gt;
	&lt;li&gt;ये पेड़ &lt;strong&gt;&lt;span style=&quot;color: (33, 37, 41);&quot;&gt;पर्वतीय&lt;/span&gt;&lt;strong&gt; &lt;/strong&gt;शीतोष्ण वन&lt;/strong&gt; में पाए जाते हैं।&lt;/li&gt;
	&lt;li&gt;इस प्रकार के वन मुख्य रूप से उत्तरी मध्य हिमालय और दक्षिणी नीलगिरी उच्च पर्वत श्रृंखलाओं में उत्पन्न होते हैं।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;हरियाणा के अर्ध-रेगिस्तानी मैदानों में &lt;strong&gt;कीकर और खैर &lt;/strong&gt;के पेड़ पाए जाते&amp;nbsp;हैं।&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;सुंदरी वृक्ष&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;सुंदरबन में सुंदरी के पेड़ पाए जाते हैं।&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;इन वृक्षों की लकड़ी कठोर, तैलीय और टिकाऊ होती है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;इसका उपयोग नाव और अन्य निर्माण उपकरण बनाने के लिए किया जाता है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;सुंदरी वृक्ष, सुंदरबन में सबसे व्यापक रूप से पाए जाने वाले मैंग्रोव प्रजातियों में से एक है।&lt;/li&gt;
	&lt;li&gt;यह पंखों के आकार का नट वाला एक बड़ा पेड़ है, जिसे इसकी पत्तियों के नीचे चांदी के तराजू से सबसे आसानी से पहचाना जाता है।&lt;/li&gt;
	&lt;li&gt;वैज्ञानिक रूप से इसे हेरिटिएरा लिटोरेलिस के नाम से जाना जाता है।&lt;/li&gt;
	&lt;li&gt;सुंदरी वृक्ष की लकड़ी लोगों के बीच इमारती लकड़ी का प्रमुख स्रोत है।&lt;/li&gt;
	&lt;li&gt;लकड़ी कठोर और लाल रंग की होती है, और अच्छी गुणवत्ता वाले चारकोल का उत्पादन करती है,&amp;nbsp;और इसका उपयोग अक्सर नाव निर्माण, और कठोर&amp;nbsp;लकड़ी के फर्श और फर्नीचर के निर्माण में किया जाता है।&lt;/li&gt;
	&lt;li&gt;इसका उपयोग नींव, पुल और घाट बनाने में भी किया जाता है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;color: (33, 37, 41);&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&lt;span style=&quot;font-size:20px;&quot;&gt;&lt;span style=&quot;vertical-align: middle; &quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;color: (33, 37, 41); width: 400px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;वन&amp;nbsp;&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;वर्षा&amp;nbsp;&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;वनस्पति&amp;nbsp;&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;क्षेत्र&amp;nbsp;&lt;/font&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;आर्द्र उष्णकटिबंधीय&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;200 और&amp;nbsp; 250 सेमी&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;रोजवुड, बांस, कुसुम, इंडियन चेस्टनट, लिटसी&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;पश्चिमी तट, ऊपरी असम, पूर्वी हिमालय के निचले ढलान, उड़ीसा तट&lt;/font&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;शुष्क उष्णकटिबंधीय&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;51 सेमी&amp;nbsp; से&amp;nbsp; 151&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;साल, बबूल, आम और बाँस।&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;उत्तरी पहाड़ी क्षेत्र और दक्षिणी भारत के कुछ राज्य&lt;/font&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;पर्वतीय समशीतोष्ण&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;150-250 सेमी&amp;nbsp;&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;फर्नेस, ओक, मेपल, जुनिपर, देवदार, चिलगोजा, चिरपीन&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;उत्तरी मध्य हिमालय और दक्षिणी नीलगिरी ऊंची पर्वत श्रृंखलाएं।&lt;/font&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;
			&lt;p&gt;&lt;font color=&quot;&quot;&gt;&lt;span style=&quot;text-align: center;&quot;&gt;पर्वतीय&amp;nbsp;&lt;/span&gt;उपोष्णकटिबंधीय &lt;/font&gt;&lt;br /&gt;
			&amp;nbsp;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;150-300 सेमी&amp;nbsp;&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;दालचीनी, रोडोडेंड्रॉन, साल, सैंडन, लैबर्नम, अनार, जैतून, ओलियंडर&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;असम, नागालैंड, मिजोरम, मेघालय, मणिपुर, अरुणाचल प्रदेश&lt;/font&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;अल्पाइन वन/आर्द्र&amp;nbsp; पर्वतीय क्षेत्र&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;100 सेमी&amp;nbsp;&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;&quot;&gt;ब्लैक जुनिपर, ड्रोपिंग जुनिपर; हनीसकल, और विलो&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;हिमालयी क्षेत्र और ट्रांस हिमालय के बंजर शीत&amp;nbsp; रेगिस्तान&lt;/td&gt;
		&lt;/tr&gt;
